    options.propertyInvalidationErrors = ImmutableMap.of(
        "abc", CheckLevel.ERROR);

    test(options, code,
        "alert((new function(){this.abc = 1}).abc + " +
            "(new function(){this.abc = 1}).abc);");


    test(options, "" +
        " var X = function() {" +
        " this.abc = 1;};\n" +
        " var Y = function() {" +
        " this.abc = 1;};\n" +
        "alert(new X() + new Y());",
        "alert((new function(){this.abc = 1}) + " +
            "(new function(){this.abc = 1}));");
  }

