    SymbolTable table = createSymbolTable(
        " var a = {};" +
        " a.b = {};" +
        " function f(x) {}");
    Symbol a = getGlobalVar(table, "a");
    Symbol ab = getGlobalVar(table, "a.b");
    Symbol f = getGlobalVar(table, "f");
    Symbol x = getLocalVar(table, "x");
